Future<void> _handleJoinErrorPrimaryTap(
  BuildContext context, {
  required JoinRole selectedRole,
  required String reason,
}) async {
  if (reason == _joinErrorCameraPermission) {
    await openAppSettings();
    return;
  }
  if (reason == _joinErrorSessionExpired) {
    context.go(_buildAuthRouteWithNextRole(_authNextRolePassenger));
    return;
  }
  if (reason == _joinErrorQrNotSupported) {
    context.go(_buildJoinRoute(role: JoinRole.driver));
    return;
  }
  context.go(_buildJoinQrRoute(role: selectedRole));
}
